import React, { useEffect, useState } from 'react';
import TopNav from './TopNav';
import SEO from './SEO';
import './About.css';
import '../App.css';

import { httpsCallable } from "firebase/functions";
import { doc, runTransaction } from "firebase/firestore";
import { db, functions, serverTimestamp } from "../firebase";
import { useAuth } from "../auth/AuthProvider";
import { trackEvent, trackOncePerUser } from "../utils/trackEvent";


const ABOUT_TRIAL_TIMER_KEY = "chessdrills_about_trial_reserved_until";
const ABOUT_PLAYER_COUNT_KEY = "chessdrills_about_player_count";
const ABOUT_PLAYER_COUNT_BASE = 12855;
const ABOUT_TRIAL_MIN_SECONDS = 5 * 60;
const ABOUT_TRIAL_MAX_SECONDS = 10 * 60;

const aboutProofFaces = [
  "data:image/png;base64,",
  "data:image/png;base64,",
  "data:image/png;base64,",
  "data:image/png;base64,"
];

function getTrialReserveEndAt() {
  const fallbackEnd = Date.now() + ABOUT_TRIAL_MIN_SECONDS * 1000;

  if (typeof window === "undefined" || !window.sessionStorage) {
    return fallbackEnd;
  }

  try {
    const saved = Number(window.sessionStorage.getItem(ABOUT_TRIAL_TIMER_KEY));

    if (Number.isFinite(saved) && saved > Date.now()) {
      return saved;
    }

    const seconds =
      ABOUT_TRIAL_MIN_SECONDS +
      Math.floor(Math.random() * (ABOUT_TRIAL_MAX_SECONDS - ABOUT_TRIAL_MIN_SECONDS + 1));
    const nextEnd = Date.now() + seconds * 1000;
    window.sessionStorage.setItem(ABOUT_TRIAL_TIMER_KEY, String(nextEnd));
    return nextEnd;
  } catch (_) {
    return fallbackEnd;
  }
}

function getStoredPlayerCount() {
  if (typeof window === "undefined" || !window.localStorage) {
    return ABOUT_PLAYER_COUNT_BASE;
  }

  try {
    const saved = Number(window.localStorage.getItem(ABOUT_PLAYER_COUNT_KEY));
    return Number.isFinite(saved) && saved >= ABOUT_PLAYER_COUNT_BASE ? saved : ABOUT_PLAYER_COUNT_BASE;
  } catch (_) {
    return ABOUT_PLAYER_COUNT_BASE;
  }
}

function formatReserveTime(totalSeconds) {
  const safeSeconds = Math.max(0, totalSeconds);
  const minutes = Math.floor(safeSeconds / 60);
  const seconds = String(safeSeconds % 60).padStart(2, "0");
  return `${minutes}:${seconds}`;
}


export default function About(props) {
  const { user, hasPaidMembership, trialActive, trialEligible, trialExpired } = useAuth();
  const [trialBusy, setTrialBusy] = useState(false);
  const [checkoutBusy, setCheckoutBusy] = useState(false);
  const [selectedPlan, setSelectedPlan] = useState("yearly");

  const [trialReserveEndAt] = useState(getTrialReserveEndAt);
  const [trialReserveSeconds, setTrialReserveSeconds] = useState(() =>
    Math.max(0, Math.ceil((getTrialReserveEndAt() - Date.now()) / 1000))
  );
  const [playerCount, setPlayerCount] = useState(getStoredPlayerCount);

  useEffect(() => {
    const updateTimer = () => {
      setTrialReserveSeconds(Math.max(0, Math.ceil((trialReserveEndAt - Date.now()) / 1000)));
    };

    updateTimer();
    const timerId = window.setInterval(updateTimer, 1000);

    return () => window.clearInterval(timerId);
  }, [trialReserveEndAt]);

  useEffect(() => {
    if (typeof window === "undefined") return undefined;

    let timeoutId;

    const scheduleIncrement = () => {
      const delay = 90000 + Math.floor(Math.random() * 90000);

      timeoutId = window.setTimeout(() => {
        setPlayerCount((currentCount) => {
          const nextCount = currentCount + 1;

          try {
            window.localStorage.setItem(ABOUT_PLAYER_COUNT_KEY, String(nextCount));
          } catch (_) {}

          return nextCount;
        });

        scheduleIncrement();
      }, delay);
    };

    scheduleIncrement();

    return () => {
      if (timeoutId) {
        window.clearTimeout(timeoutId);
      }
    };
  }, []);


  const fromState = props && props.location && props.location.state ? props.location.state : null;
  const reason = fromState && fromState.reason ? String(fromState.reason) : "";

  const showLockedNote =
    reason === "membership_required" || reason === "member_opening" || reason === "membership_requires_account";

  const go = (url) => {
    if (!url) return;
    try {
      window.location.href = url;
    } catch (_) {}
  };

  const goToSignup = () => {
    try {
      const from = `${window.location.pathname || "/about"}${window.location.search || ""}` || "/about";
      window.location.href = `/signup?source=membership&from=${encodeURIComponent(from)}&reason=membership_requires_account`;
    } catch (_) {}
  };

  const goBack = () => {
    const rawFrom = fromState && typeof fromState.from === "string" ? fromState.from : "";
    const from = rawFrom.indexOf("#/") === 0 ? rawFrom.slice(1) : rawFrom;

    if (props && props.history && typeof props.history.replace === "function" && from && from.charAt(0) === "/") {
      props.history.replace(from);
      return;
    }

    try {
      window.location.href = from && from.charAt(0) === "/" ? from : "/openings";
    } catch (_) {}
  };

  const startFreeTrial = async () => {
    if (!user) {
      goToSignup();
      return;
    }

    if (hasPaidMembership || trialActive) {
      goBack();
      return;
    }

    if (!trialEligible) {
      alert("This account has already used its free trial.");
      return;
    }

    setTrialBusy(true);
    try {
      const ref = doc(db, "users", user.uid);
      await runTransaction(db, async (tx) => {
        const snap = await tx.get(ref);
        const data = snap.exists() ? (snap.data() || {}) : {};
        const membershipTier = data.membershipTier || "free";
        const hasActiveMembership = !!data.membershipActive && (membershipTier === "member" || membershipTier === "lifetime");

        if (hasActiveMembership || data.trialUsed || data.trialStartedAt) {
          throw new Error("trial_unavailable");
        }

        tx.set(ref, {
          trialUsed: true,
          trialStartedAt: serverTimestamp(),
          updatedAt: serverTimestamp()
        }, { merge: true });
      });

      trackOncePerUser(user, "trial_start", { source: "about_free_trial", plan: "free_trial" });
      goBack();
    } catch (_) {
      alert("Could not start the free trial. Please try again.");
    } finally {
      setTrialBusy(false);
    }
  };

  const startPaidCheckout = async () => {
    if (!user) {
      goToSignup();
      return;
    }

    trackEvent("checkout_start", { source: "about", plan: selectedPlan }, user);
    setCheckoutBusy(true);
    try {
      const fn = httpsCallable(functions, "createCheckoutSession");
      const res = await fn({ tier: "member", plan: selectedPlan });
      const url = res && res.data && res.data.url ? String(res.data.url) : "";

      if (!url) {
        throw new Error("checkout_missing_url");
      }

      go(url);
    } catch (e) {
      const code = e && e.code ? String(e.code) : "unknown";
      const message = e && e.message ? String(e.message) : "Checkout failed.";
      console.error("Checkout failed", { code, message, plan: selectedPlan, error: e });

      if (code === "functions/unauthenticated") {
        alert("Please sign in before starting checkout.");
      } else {
        alert("Checkout failed. Please try again in a moment.");
      }
    } finally {
      setCheckoutBusy(false);
    }
  };

  const selectPlan = (plan) => {
    if (plan !== "monthly" && plan !== "yearly") return;
    setSelectedPlan(plan);
  };

  return (
    <div className="about-page">
      <SEO
        title="ChessDrills Premium | ChessDrills"
        description="Start a ChessDrills free trial or join premium to unlock more opening training features."
        canonical="https://chessdrills.net/about"
        image="https://chessdrills.net/logo512.png"
      />

      <TopNav active="about" title="Chess Opening Drills" />

      <div className="about-wrap">
        <div className="about-card">
          <div className="about-hero">
            
            <h2 className="about-title">Try Chessdrills free for 3 days</h2>
            <p className="about-lead">after that, join for $39/year or $5.99/month.</p>

          </div>

          {showLockedNote ? (
            <div className="about-note">
              <div className="about-note-title">That feature is Premium only.</div>
              <div className="about-note-sub">Start the free trial to unlock it right away, or join now and subscribe through Stripe.</div>
            </div>
          ) : null}

          <div className="about-section">
            <div className="about-section-title">Choose a plan</div>

            <div className="about-tiers">
              <button
                type="button"
                className={"about-tier " + (selectedPlan === "yearly" ? "selected" : "")}
                onClick={() => selectPlan("yearly")}
              >
                <div className="about-tier-top">
                  <div className="about-tier-name">
                    Yearly
                    <span className="about-tier-tag">Best value</span>
                  </div>
                  <div className="about-tier-price">$39 / year</div>
                </div>
                <div className="about-tier-desc">
                  Only $3.25/month.
                </div>
                <div className="about-tier-check" aria-hidden="true">
                  <span className="about-tier-check-dot" />
                </div>
              </button>

              <button
                type="button"
                className={"about-tier " + (selectedPlan === "monthly" ? "selected" : "")}
                onClick={() => selectPlan("monthly")}
              >
                <div className="about-tier-top">
                  <div className="about-tier-name">Monthly</div>
                  <div className="about-tier-price">$5.99 / month</div>
                </div>
                <div className="about-tier-desc">
                  More flexible. Cancel anytime.
                </div>
                <div className="about-tier-check" aria-hidden="true">
                  <span className="about-tier-check-dot" />
                </div>
              </button>
            </div>

            <div className="about-cta-row">
              <button
                className="about-tier-btn"
                type="button"
                onClick={startFreeTrial}
                disabled={trialBusy || checkoutBusy || hasPaidMembership || (!trialActive && !trialEligible)}
              >
                {trialBusy
                  ? "Starting trial..."
                  : hasPaidMembership
                  ? "Already subscribed"
                  : trialActive
                  ? "Trial active"
                  : trialEligible
                  ? (
                    <>
                      <span>Start 3 Day Free Trial</span>
                      <span className="about-trial-button-time">{formatReserveTime(trialReserveSeconds)}</span>
                    </>
                  )
                  : "Trial already used"}
              </button>

              <button
                className="about-tier-btn secondary"
                type="button"
                onClick={startPaidCheckout}
                disabled={trialBusy || checkoutBusy}
              >
                {checkoutBusy ? "Opening checkout..." : "Join Now"}
              </button>
            </div>

            <div className="about-muted" style={{ marginTop: 10, marginBottom: 0 }}>
              No risk, no payment today, cancel anytime
            </div>

            <div className="about-proof-strip" aria-live="polite">
              <div className="about-proof-count">
                <div className="about-proof-faces" aria-hidden="true">
                  {aboutProofFaces.map((face, index) => (
                    <img key={index} src={face} alt="" />
                  ))}
                </div>
                <span><strong>{playerCount.toLocaleString()}</strong> players joined ChessDrills this year</span>
              </div>
            </div>


            {trialActive ? (
              <div className="about-inline-note">
                <div className="about-inline-note-title">Free trial is active</div>
                <div className="about-inline-note-sub">Your trial is running now. Join before it ends to keep access without interruption.</div>
              </div>
            ) : null}

            {trialExpired ? (
              <div className="about-inline-note warning">
                <div className="about-inline-note-title">Free trial ended</div>
                <div className="about-inline-note-sub">This account already used its 3 day trial. Join now to unlock premium features again.</div>
              </div>
            ) : null}
          </div>
        <div className="about-section">
          <div className="about-section-title">What you get</div>

            <ul className="about-bullets">
              <li><span role="img" aria-label="star">⭐</span> Unlimited access to all opening courses</li>
              <li><span role="img" aria-label="book">📖</span> Spaced repetition for long-term memory</li>
              <li><span role="img" aria-label="fire">🔥</span> Master lines for both White and Black</li>
              <li><span role="img" aria-label="rocket">🚀</span> Unlock all game modes, personal mistake puzzles, game analysis, and notation trainer</li>
            </ul>
          </div>

          <div className="about-section">

          </div>

          <div
  className="about-muted"
  style={{
    marginTop: 10,
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    gap: 28,
    flexWrap: "wrap",
    fontWeight: 800,
    color: "#f8fafc",
  }}
>
  <span style={{ display: "inline-flex", alignItems: "center", gap: 8 }}>
    <span aria-hidden="true">👑</span>
    3K+ active players
  </span>

  <span style={{ display: "inline-flex", alignItems: "center", gap: 8 }}>
    <span aria-hidden="true">📖</span>
    25+ courses
  </span>

  <span style={{ display: "inline-flex", alignItems: "center", gap: 8 }}>
    <span aria-hidden="true">⭐</span>
    4.9 rating
  </span>
</div>


        </div>
      </div>
    </div>
  );
}
